1. /**
2.  * Model routing policy — single source of truth.
3.  *
4.  * MODEL_CANDIDATES is the authoritative runtime data. Everything else—
5.  * MODEL_FAMILIES, routing-matrix.md tables, and the README Model Coverage
6.  * section—is derived from or mirrors this object. Update here first, then
7.  * reflect the change in the human-readable documents.
8.  *
9.  * This module is pure (no SDK imports, no side effects) so it can be
10.  * imported by both extension.mjs and the test suite.
11.  */
12. 
13. // ---------------------------------------------------------------------------
14. // Tier definitions
15. // ---------------------------------------------------------------------------
16. 
17. export const MODEL_CANDIDATES = {
18.   economy: [
19.     { id: "claude-haiku-4.5", reasoningEffort: null },
20.     { id: "gpt-4.1", reasoningEffort: null },
21.     { id: "gpt-5-mini", reasoningEffort: "low" },
22.     { id: "gpt-5.4-mini", reasoningEffort: "low" },
23.   ],
24.   builder: [
25.     // Reasoning-capable models listed first for better implementation quality
26.     { id: "claude-sonnet-4.6", reasoningEffort: "medium" },
27.     { id: "gpt-5.2", reasoningEffort: "medium" },
28.     { id: "gpt-5.3-codex", reasoningEffort: "medium" },
29.     { id: "gpt-5.1-codex", reasoningEffort: "medium" },
30.     { id: "gpt-5.1", reasoningEffort: "medium" },
31.     // Non-reasoning fallbacks
32.     { id: "claude-sonnet-4", reasoningEffort: null },
33.     { id: "claude-sonnet-4.5", reasoningEffort: null },
34.   ],
35.   reasoning: [
36.     { id: "gpt-5", reasoningEffort: "high" },
37.     { id: "gpt-5.4", reasoningEffort: "high" },
38.     { id: "claude-sonnet-4.6", reasoningEffort: "high" },
39.     { id: "claude-opus-4.5", reasoningEffort: null },
40.     { id: "claude-opus-4.6", reasoningEffort: null },
41.     { id: "claude-opus-4.6-1m", reasoningEffort: null },
42.     { id: "gpt-5.1-codex-max", reasoningEffort: "high" },
43.   ],
44. };
45. 
46. // Derived automatically from MODEL_CANDIDATES so it never drifts.
47. // When you add or remove a model above, this stays correct for free.
48. export const MODEL_FAMILIES = (() => {
49.   const claude = new Set();
50.   const gpt = new Set();
51.   for (const tier of Object.values(MODEL_CANDIDATES)) {
52.     for (const { id } of tier) {
53.       if (id.startsWith("claude")) claude.add(id);
54.       else if (id.startsWith("gpt")) gpt.add(id);
55.     }
56.   }
57.   return { claude, gpt };
58. })();
59. 
60. // ---------------------------------------------------------------------------
61. // Keyword lists
62. // ---------------------------------------------------------------------------
63. 
64. export const EXPLICIT_REVIEW_KEYWORDS = [
65.   "review",
66.   "code review",
67.   "review this",
68.   "review the code",
69.   "review my code",
70.   "audit",
71.   "approval readiness",
72.   "approval readiness checks",
73.   "approve this",
74.   "pr review",
75.   // Bug finding, regression hunting, and approval-readiness are explicit review asks per SKILL.md
76.   "find bugs",
77.   "bug finding",
78.   "regression hunting",
79.   "regression hunt",
80.   "find regressions",
81. ];
82. 
83. export const PLAN_KEYWORDS = [
84.   "plan",
85.   "design",
86.   "architecture",
87.   "architect",
88.   "proposal",
89.   "strategy",
90.   "approach",
91. ];
92. 
93. export const DEBUG_KEYWORDS = [
94.   "debug",
95.   "fix",
96.   "failure",
97.   "failing",
98.   "error",
99.   "crash",
100.   "root cause",
101.   "broken",
102.   "investigate",
103. ];
104. 
105. export const IMPLEMENT_KEYWORDS = [
106.   "implement",
107.   "build",
108.   "create",
109.   "write",
110.   "refactor",
111.   "add",
112.   "change",
113.   "update",
114.   "edit",
115.   "enhance",
116.   "modify",
117.   "adjust",
118.   "improve",
119.   "fix the code",
120.   "fix the formatting",
121.   "fix the logic",
122. ];
123. 
124. export const LIGHT_KEYWORDS = [
125.   "explain",
126.   "summarize",
127.   "what is",
128.   "where is",
129.   "find",
130.   "list",
131.   "show",
132.   "search",
133. ];
134. 
135. export const TOOL_KEYWORDS = [
136.   "bash",
137.   "curl",
138.   "execute",
139.   "run",
140.   "tool",
141.   "api",
142.   "function",
143.   "call",
144.   "invoke",
145.   "script",
146.   "command",
147.   "shell",
148.   "http",
149.   "request",
150.   "endpoint",
151.   "agent",
152. ];
153. 
154. // Complex multi-tool orchestration patterns warrant reasoning-tier escalation.
155. // Only multi-word action phrases are included; bare "orchestrate"/"orchestration" caused
156. // false positives when tasks merely mentioned these concepts in documentation context.
157. export const ORCHESTRATION_KEYWORDS = [
158.   "parallel agents",
159.   "multiple agents",
160.   "multi-agent",
161.   "parallel tools",
162.   "tool chain",
163.   "chained tools",
164. ];
165. 
166. // ---------------------------------------------------------------------------
167. // Pure helper functions
168. // ---------------------------------------------------------------------------
169. 
170. export function getModelFamily(modelId) {
171.   if (!modelId) return null;
172.   if (MODEL_FAMILIES.claude.has(modelId)) return "claude";
173.   if (MODEL_FAMILIES.gpt.has(modelId)) return "gpt";
174.   return null;
175. }
176. 
177. export function normalizePrompt(prompt) {
178.   return String(prompt || "").toLowerCase();
179. }
180. 
181. // Word-boundary-aware matching prevents false positives like "prefix"→"fix",
182. // "exchange"→"change", "callback"→"call". Multi-word phrases use substring matching.
183. export function matchesPattern(text, pattern) {
184.   if (/\s/.test(pattern)) {
185.     return text.includes(pattern);
186.   }
187.   const escaped = pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
188.   return new RegExp(`\\b${escaped}\\b`).test(text);
189. }
190. 
191. export function includesAny(text, patterns) {
192.   return patterns.some((pattern) => matchesPattern(text, pattern));
193. }
194. 
195. export function isExplicitReviewRequest(text) {
196.   return includesAny(text, EXPLICIT_REVIEW_KEYWORDS);
197. }
198. 
199. export function isToolHeavy(text) {
200.   return includesAny(text, TOOL_KEYWORDS);
201. }
202. 
203. export function isComplexOrchestration(text) {
204.   return includesAny(text, ORCHESTRATION_KEYWORDS);
205. }
206. 
207. export function getComplexity(prompt) {
208.   const lower = normalizePrompt(prompt);
209.   const words = lower.trim().split(/\s+/).filter(Boolean).length;
210.   let score = 0;
211. 
212.   if (words > 40) score += 1;
213.   if (words > 100) score += 1;
214.   if (
215.     includesAny(lower, [
216.       "multi-file",
217.       "multiple files",
218.       "end-to-end",
219.       "carefully",
220.       "thorough",
221.       "deep",
222.       "complex",
223.       "large",
224.       "entire codebase",
225.     ])
226.   ) {
227.     score += 2;
228.   }
229. 
230.   if (includesAny(lower, PLAN_KEYWORDS) || includesAny(lower, DEBUG_KEYWORDS)) {
231.     score += 1;
232.   }
233. 
234.   // File path detection (/.github/, /src/, /lib/, etc.) indicates code changes
235.   if (/\/[\w-]+\/[\w.-]+/.test(lower)) {
236.     score += 1;
237.   }
238. 
239.   if (isToolHeavy(lower)) {
240.     score += 1;
241.   }
242. 
243.   return score;
244. }
245. 
246. export function classifyPrompt(prompt) {
247.   const lower = normalizePrompt(prompt);
248.   const complexity = getComplexity(lower);
249. 
250.   if (isExplicitReviewRequest(lower)) {
251.     return { kind: "review", complexity, tier: "reasoning" };
252.   }
253. 
254.   if (includesAny(lower, PLAN_KEYWORDS)) {
255.     return {
256.       kind: "planning",
257.       complexity,
258.       tier: complexity >= 3 ? "reasoning" : "builder",
259.     };
260.   }
261. 
262.   if (includesAny(lower, DEBUG_KEYWORDS)) {
263.     return {
264.       kind: "debugging",
265.       complexity,
266.       tier: complexity >= 3 ? "reasoning" : "builder",
267.     };
268.   }
269. 
270.   if (includesAny(lower, IMPLEMENT_KEYWORDS)) {
271.     let tier = "builder"; // default to builder for all implementation
272. 
